namespace InventoryApp.Services;

public record EquipmentItem(
    int Id,
    string Name,
    string Location,
    DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a slow data source
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A",       "Warehouse 1", new DateTime(2026, 4, 10)),
            new(2, "Conveyor Belt B",   "Warehouse 2", new DateTime(2026, 3, 22)),
            new(3, "Drill Press C",     "Shop Floor",  new DateTime(2026, 5, 1)),
            new(4, "Lathe D",          "Shop Floor",  new DateTime(2025, 12, 15)),
            new(5, "Pallet Jack E",    "Warehouse 1", new DateTime(2026, 5, 20)),
            new(6, "CNC Router F",     "Shop Floor",  new DateTime(2026, 1, 8)),
            new(7, "Hoist Crane G",    "Warehouse 3", new DateTime(2026, 2, 28)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState PersistentState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSubscription;

    protected override async Task OnInitializedAsync()
    {
        // During interactive reconnect, restore the data that was already
        // fetched during prerender — no second service call needed.
        if (PersistentState.TryTakeFromJson<List<EquipmentItem>>(
                nameof(_items), out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentService.GetEquipmentAsync();
        }

        // Register a callback so the prerender pass persists the data
        // into the page HTML for the interactive runtime to pick up.
        _persistSubscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson(nameof(_items), _items);
            return Task.CompletedTask;
        });
    }

    public void Dispose()
    {
        _persistSubscription.Dispose();
    }
}

